// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Certificados {
    
    // Dirección del administrador del contrato (la institución académica)
    address public owner;

    // Estructura interna para almacenar los metadatos del certificado
    struct Certificado {
        string nombreTitular;
        uint256 fechaEmision;
        bool esValido;
    }

    // Mapeo clave-valor para asociar el código del certificado con sus datos
    mapping(string => Certificado) private registros;

    // Eventos para auditar las acciones en la blockchain
    event CertificadoRegistrado(string codigo, string nombreTitular, uint256 fecha);
    event CertificadoRevocado(string codigo, uint256 fechaRevocacion);

    // Modificador para restringir funciones únicamente al administrador
    modifier onlyOwner() {
        require(msg.sender == owner, "Acceso denegado: Solo el administrador puede ejecutar esta accion.");
        _;
    }

    // Constructor que define al emisor inicial del contrato
    constructor() {
        owner = msg.sender;
    }

    /**
     * @notice Registra un nuevo certificado académico en la blockchain
     * @param _codigo Identificador único del certificado (Ej: UNSA-2026-0041)
     * @param _nombreTitular Nombre completo del estudiante graduado
     */
    function registrarCertificado(string memory _codigo, string memory _nombreTitular) public onlyOwner {
        // Validación para evitar duplicados y sobrescritura de datos existentes
        require(registros[_codigo].fechaEmision == 0, "Error: El codigo de certificado ya se encuentra registrado.");
        // Validación de campos vacíos
        require(bytes(_nombreTitular).length > 0, "Error: El nombre del titular no puede estar vacio.");

        registros[_codigo] = Certificado({
            nombreTitular: _nombreTitular,
            fechaEmision: block.timestamp,
            esValido: true
        });

        emit CertificadoRegistrado(_codigo, _nombreTitular, block.timestamp);
    }

    /**
     * @notice Verifica la autenticidad y estado de un certificado
     * @param _codigo Código identificador a consultar
     * @return nombre Nombre del titular del certificado
     * @return fecha Fecha exacta de emisión (Timestamp)
     * @return validez Estado actual del documento (true = válido, false = revocado o inexistente)
     */
    function verificarCertificado(string memory _codigo) public view returns (
        string memory nombre, 
        uint256 fecha, 
        bool validez
    ) {
        Certificado memory cert = registros[_codigo];
        // Si la fecha es 0 significa que el registro no existe en el mapeo
        require(cert.fechaEmision != 0, "Error: El certificado consultado no existe.");
        
        return (cert.nombreTitular, cert.fechaEmision, cert.esValido);
    }

    /**
     * @notice Invalida de forma permanente o preventiva un certificado emitido
     * @param _codigo Código del certificado a dar de baja
     */
    function revocarCertificado(string memory _codigo) public onlyOwner {
        require(registros[_codigo].fechaEmision != 0, "Error: El certificado a revocar no existe.");
        require(registros[_codigo].esValido == true, "Error: El certificado ya se encuentra invalidado.");

        registros[_codigo].esValido = false;

        emit CertificadoRevocado(_codigo, block.timestamp);
    }
}

